        if (rowIsOdd < 0.5 && colIsOdd >= 0.5) logicIdx = 1.0;
        else if (rowIsOdd >= 0.5 && colIsOdd < 0.5) logicIdx = 3.0;
        else if (rowIsOdd >= 0.5 && colIsOdd >= 0.5) logicIdx = 2.0;

